import GLightbox from 'glightbox';
import 'glightbox/dist/css/glightbox.min.css';
import $ from 'cash-dom';

/**
 * Gère l'affichage des images et vidéos en plein écran.
 * Utilise la délégation d'événements via cash-dom pour supporter les éléments dynamiques.
 */
export class LightBox {
    /**
     * @param {string} selector - Le sélecteur CSS des éléments à inclure (ex: '.lightbox')
     */
    constructor(selector = '.lightbox') {
        this.selector = selector;
        /** @type {any} */
        this.instance = null;
        this.init();
    }

    /**
     * Initialise la délégation d'événements.
     * @returns {void}
     */
    init() {
        // On initialise GLightbox sans sélecteur automatique pour garder le contrôle
        this.instance = GLightbox({
            touchNavigation: true,
            loop: true,
        });

        // Délégation d'événement via cash-dom
        $(document).on('click', this.selector, (event) => {
            event.preventDefault();
            const element = event.currentTarget;

            // On ouvre manuellement l'élément cliqué
            this.instance.setElements([element]);
            this.instance.open();

            // Si l'élément appartient à une galerie, on recharge les éléments de cette galerie
            const galleryName = $(element).attr('data-gallery');
            if (galleryName) {
                const galleryElements = $(`${this.selector}[data-gallery="${galleryName}"]`).get();
                this.instance.setElements(galleryElements);
                const index = galleryElements.indexOf(element);
                this.instance.openAt(index);
            }
        });

        console.log(`LightBox prête (délégation sur : ${this.selector})`);
    }

    /**
     * Nettoyage si le composant est retiré (utile pour les Single Page Apps)
     */
    destroy() {
        if (this.instance) {
            this.instance.destroy();
        }
    }
}

import GLightbox from 'glightbox';
import 'glightbox/dist/css/glightbox.min.css';
import $ from 'cash-dom';

/**
 * Gère l'affichage des images et vidéos en plein écran.
 * Utilise la délégation d'événements via cash-dom pour supporter les éléments dynamiques.
 */
export class LightBox {
    /**
     * @param {string} selector - Le sélecteur CSS des éléments à inclure (ex: '.lightbox')
     */
    constructor(selector = '.lightbox') {
        this.selector = selector;
        /** @type {any} */
        this.instance = null;
        this.init();
    }

    /**
     * Initialise la délégation d'événements.
     * @returns {void}
     */
    init() {
        // On initialise GLightbox sans sélecteur automatique pour garder le contrôle
        this.instance = GLightbox({
            touchNavigation: true,
            loop: true,
        });

        // Délégation d'événement via cash-dom
        $(document).on('click', this.selector, (event) => {
            event.preventDefault();
            event.stopImmediatePropagation(); // Empêche d'autres déclencheurs potentiels

            const element = event.currentTarget;

            // Si la lightbox est déjà ouverte, on ne fait rien
            if (this.instance.built && this.instance.isOpen()) {
                return;
            }

            // On récupère les éléments de la galerie ou l'élément seul
            const galleryName = $(element).attr('data-gallery');
            let galleryElements = [element];
            let index = 0;

            if (galleryName) {
                galleryElements = $(`${this.selector}[data-gallery="${galleryName}"]`).get();
                index = galleryElements.indexOf(element);
            }

            // Mise à jour des éléments et ouverture
            this.instance.setElements(galleryElements);
            this.instance.openAt(index);
        });

        console.log(`LightBox prête (délégation sur : ${this.selector})`);
    }

    /**
     * Nettoyage si le composant est retiré (utile pour les Single Page Apps)
     */
    destroy() {
        if (this.instance) {
            this.instance.destroy();
        }
    }
}

import {Embla} from "@comp/carousel/engine/embla/embla.js";
import Alpine from "alpinejs";
import {LightBox} from "@comp/light-box/LightBox.js";
import {Web3Form} from "@comp/web3-form/Web3Form.js";
import {Share} from "@comp/share/Share.js";
import $ from "cash-dom";

// On expose cash au besoin dans le window
window.$ = $;
window.cash = $;

document.addEventListener('alpine:init', () => {
    console.log("Alpine init")
    // slide show
    Alpine.data('embla', (args) => new Embla(args));

    // light box global
    const globalLightbox = new LightBox('.lightbox, .glightbox');
    // On l'enregistre dans le store
    Alpine.store('lightbox', globalLightbox);

    // Formulaire Web3Forms
    Alpine.data('web3Forms', () => new Web3Form());

    // Partage natif (Web Share API)
    Alpine.data('share', () => new Share());
});

// ─── Alpine.js ────────────────────────────────────────────────────────────────

globalThis.Alpine = Alpine;
window.Alpine = Alpine;
Alpine.start();

import {Embla} from "@comp/carousel/engine/embla/embla.js";
import Alpine from "alpinejs";
import {LightBox} from "@comp/light-box/LightBox.js";
import {Web3Form} from "@comp/web3-form/Web3Form.js";
import {Share} from "@comp/share/Share.js";
import {SwiperCarousel} from "@comp/carousel/swiper/SwiperCarousel.js";
import $ from "cash-dom";

// On expose cash au besoin dans le window
window.$ = $;
window.cash = $;

document.addEventListener('alpine:init', () => {
    console.log("Alpine init")
    // slide show
    Alpine.data('embla', (args) => new Embla(args));

    // light box global
    const globalLightbox = new LightBox('.lightbox, .glightbox');
    // On l'enregistre dans le store
    Alpine.store('lightbox', globalLightbox);

    // Formulaire Web3Forms
    Alpine.data('web3Forms', () => new Web3Form());

    // Partage natif (Web Share API)
    Alpine.data('share', () => new Share());

    // Composant Swiper
    Alpine.data('swiper', (args) => new SwiperCarousel(args));
});

// ─── Alpine.js ────────────────────────────────────────────────────────────────

globalThis.Alpine = Alpine;
window.Alpine = Alpine;
Alpine.start();

import Swiper from 'swiper'
import { FreeMode, Autoplay, Navigation, Pagination } from 'swiper/modules'
import 'swiper/css'

/**
 * Composant Alpine.js pour Swiper.
 * Accepte toutes les options natives Swiper.
 * La navigation et la pagination sont gérées nativement par Swiper
 * via les éléments `.swiper-button-prev`, `.swiper-button-next`, `.swiper-pagination`.
 */
export class SwiperCarousel {
    /** @param {import('swiper/types').SwiperOptions} options */
    constructor(options = {}) {
        this.options = options;
    }

    /** @this {SwiperCarousel & { $el: HTMLElement }} */
    init() {
        new Swiper(this.$el, {
            modules: [FreeMode, Autoplay, Navigation, Pagination],
            grabCursor: true,
            ...this.options,
        });
    }
}
